# Auto-generated by tdd_orchestrator.py — Stage: square_centered
"""
TDD Stage: square_centered
Add square phase after mean subtraction. Output is (x - mean)^2 element-wise.
"""

import pytest
import torch
import ttnn

from .layer_norm_rm import layer_norm_rm


def pytorch_reference(x):
    """PyTorch reference for this stage."""
    return (x - x.mean(dim=-1, keepdim=True)).pow(2)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 32, 128), id="1x1x32x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_square_centered(device, shape):
    """Verify output = (x - mean(x, dim=-1))^2."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.ROW_MAJOR_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm_rm(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.05,
        atol=0.5,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
